import{_ as a,c as i,o,a2 as t}from"./chunks/framework.CIiVzG-O.js";const p=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1776396452000}'),n={name:"guide/installation.md"};function r(l,e,s,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="download-nicasa" tabindex="-1">Download Nicasa <a class="header-anchor" href="#download-nicasa" aria-label="Permalink to &quot;Download Nicasa&quot;">​</a></h2><p>Nicasa is available exclusively for macOS through the Mac App Store. The app costs $4.99 and provides a one-time purchase for full access to all features.</p><h3 id="download-options" tabindex="-1">Download Options <a class="header-anchor" href="#download-options" aria-label="Permalink to &quot;Download Options&quot;">​</a></h3><ul><li><strong>Mac App Store</strong>: <a href="https://apps.apple.com/us/app/nicasa-image-viewer/id6756032669?mt=12" target="_blank" rel="noreferrer">Download Nicasa</a> - $4.99</li><li><strong>Chrome Extension</strong>: <a href="https://chromewebstore.google.com/detail/nicasa-Image-viewer/cihceekeiedkinpjjjfehlgjdhpeokbj" target="_blank" rel="noreferrer">Free Chrome Extension</a> - Free</li></ul><h2 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h2><h3 id="mac-app-store-installation" tabindex="-1">Mac App Store Installation <a class="header-anchor" href="#mac-app-store-installation" aria-label="Permalink to &quot;Mac App Store Installation&quot;">​</a></h3><ol><li>Click the &quot;Download Nicasa&quot; link above or search for &quot;Nicasa&quot; in the Mac App Store</li><li>Click &quot;Get&quot; or &quot;Buy&quot; to purchase the app ($4.99)</li><li>The app will automatically download and install</li><li>Launch Nicasa from your Applications folder or Launchpad</li></ol><h3 id="chrome-extension-installation" tabindex="-1">Chrome Extension Installation <a class="header-anchor" href="#chrome-extension-installation" aria-label="Permalink to &quot;Chrome Extension Installation&quot;">​</a></h3><ol><li>Visit the <a href="https://chromewebstore.google.com/detail/nicasa-Image-viewer/cihceekeiedkinpjjjfehlgjdhpeokbj" target="_blank" rel="noreferrer">Chrome Web Store page</a></li><li>Click &quot;Add to Chrome&quot;</li><li>Confirm the installation in the popup</li><li>The extension will be added to your browser</li></ol><h2 id="first-launch" tabindex="-1">First Launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First Launch&quot;">​</a></h2><p>When you launch Nicasa for the first time:</p><ol><li>You&#39;ll be prompted to grant necessary permissions (screen recording for screenshots)</li><li>The application will scan for images in your Pictures folder</li><li>You can start browsing your collection immediately</li><li>Consider installing the Chrome extension for enhanced web browsing</li></ol><h3 id="finder-sync-extension" tabindex="-1">Finder Sync Extension <a class="header-anchor" href="#finder-sync-extension" aria-label="Permalink to &quot;Finder Sync Extension&quot;">​</a></h3><p>Nicasa includes a Finder toolbar extension for quick image processing:</p><ol><li>After launching Nicasa, go to <strong>System Settings</strong> → <strong>Extensions</strong> → <strong>Finder Extensions</strong></li><li>Enable <strong>Nicasa Finder Sync</strong></li><li>Right-click the Finder toolbar → <strong>Customize Toolbar...</strong></li><li>Drag the Nicasa button to add it to your toolbar</li></ol><p>This allows you to optimize or edit selected images directly from Finder.</p><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>macOS</strong>: 10.13 or later</li><li><strong>Storage</strong>: 54.5 MB available space</li><li><strong>Memory</strong>: 4GB RAM minimum, 8GB recommended</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Nicasa requires the following permissions:</p><ul><li><strong>Screen Recording</strong>: For screenshot functionality (can be granted later)</li><li><strong>Accessibility</strong>: For overlay mode features (optional)</li><li><strong>Files and Folders</strong>: Access to Pictures folder and user-selected directories</li></ul><p>You can modify these permissions at any time in System Settings &gt; Privacy &amp; Security.</p><h2 id="troubleshooting-installation" tabindex="-1">Troubleshooting Installation <a class="header-anchor" href="#troubleshooting-installation" aria-label="Permalink to &quot;Troubleshooting Installation&quot;">​</a></h2><p>If you encounter issues during installation:</p><ul><li>Ensure you have administrator/root privileges</li><li>Check that your system meets the minimum requirements</li><li>Try downloading the file again</li><li>For Linux, ensure you have the required dependencies installed</li></ul><p>For more help, visit our <a href="https://github.com/nicasa-project/nicasa-support/issues" target="_blank" rel="noreferrer">Issues page</a>.</p>',27)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
